# ==========================================
# 2. THE CUSTOM INFERENCE FUNCTION
# ==========================================
def generate_report(image):
    if image is None:
        return "Please upload an X-ray image.", None

    image = image.convert("RGB")

    with torch.no_grad():
        pixel_values = vision_processor(images=image, return_tensors="pt").pixel_values.to(device)

        # STRICT AUTOCAST (Matches Training Math)
        with torch.amp.autocast(device_type="cuda", dtype=torch.float16):
            vision_outputs = vision_encoder(pixel_values)
            patch_embeddings = vision_outputs.last_hidden_state.to(torch.float16)

            # EXTRACT THE ATTENTION WEIGHTS
            visual_prefix, attn_weights = projector(patch_embeddings, return_attention=True)

            messages = [
                {"role": "system", "content": "You are an expert radiologist. Analyze the chest radiograph and generate a clinical report."},
                {"role": "user", "content": "Generate a concise clinical report for this radiograph."}
            ]
            prompt_text = tokenizer.apply_chat_template(messages, tokenize=False, add_generation_prompt=True)
            text_inputs = tokenizer(prompt_text, return_tensors="pt").to(device)
            text_embeds = efficient_llm.get_input_embeddings()(text_inputs.input_ids)

            inputs_embeds = torch.cat([visual_prefix, text_embeds], dim=1)
            visual_mask = torch.ones((1, 64), dtype=torch.long, device=device)
            attention_mask = torch.cat([visual_mask, text_inputs.attention_mask], dim=1)

            generated_ids = efficient_llm.generate(
                inputs_embeds=inputs_embeds,
                attention_mask=attention_mask,
                max_new_tokens=150,
                do_sample=False,
                repetition_penalty=1.1,
                pad_token_id=tokenizer.pad_token_id
            )

        report = tokenizer.decode(generated_ids[0], skip_special_tokens=True).strip()

        # ==========================================
        # HEATMAP PROCESSING
        # ==========================================
        avg_attention = attn_weights.squeeze(0).mean(dim=0)


        grid_size = int(math.sqrt(avg_attention.shape[0]))
        actual_patches = grid_size * grid_size


        attention_grid = avg_attention[-actual_patches:].view(1, 1, grid_size, grid_size).to(torch.float32)

        original_w, original_h = image.size
        upscaled_attention = F.interpolate(attention_grid, size=(original_h, original_w), mode='bilinear', align_corners=False)

        heatmap_data = upscaled_attention.squeeze().cpu().numpy()
        heatmap_data = (heatmap_data - heatmap_data.min()) / (heatmap_data.max() - heatmap_data.min() + 1e-8)

        # Plot over original image
        fig = plt.figure(figsize=(4, 4), dpi=100)
        ax = fig.add_subplot(111)
        ax.imshow(image, cmap='gray')
        ax.imshow(heatmap_data, cmap='jet', alpha=0.5)
        ax.axis('off')
        fig.tight_layout(pad=0)

        canvas = FigureCanvas(fig)
        canvas.draw()


        heatmap_img = np.asarray(canvas.buffer_rgba())[..., :3]
        plt.close(fig)

    return report, heatmap_img


